import React from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import Home from './pages/Home';

function App() {
  return (
    <Router>
      <div className="App">
        <nav style={{ backgroundColor: '#0056b3', padding: '15px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <Link to="/" style={{ color: 'white', fontWeight: 'bold', textDecoration: 'none', fontSize: '20px' }}>APNI MANZIL</Link>
          <Link to="/login" style={{ backgroundColor: '#28a745', color: 'white', padding: '8px 20px', borderRadius: '20px', textDecoration: 'none' }}>Login</Link>
        </nav>

        <Routes>
          <Route path="/" element={<Home />} />
          {/* Jar Login.js banvli asel tarach ha khaliil line active kara, nahitar error yeil */}
          {/* <Route path="/login" element={<h1>Login Page Coming Soon</h1>} /> */}
        </Routes>
      </div>
    </Router>
  );
}

export default App;
